CREATE TABLE addresses (address_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(user_id) ON DELETE CASCADE, line1 VARCHAR(255) NOT NULL, line2 VARCHAR(255), city VARCHAR(100) NOT NULL, state VARCHAR(100) NOT NULL, pincode VARCHAR(10) NOT NULL, latitude DECIMAL(9,6), longitude DECIMAL(9,6), contact_name VARCHAR(100), contact_phone VARCHAR(15), is_default BOOLEAN NOT NULL DEFAULT FALSE, is_deleted BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE user_locations (user_id UUID PRIMARY KEY REFERENCES users(user_id) ON DELETE CASCADE, latitude DECIMAL(9,6) NOT NULL, longitude DECIMAL(9,6) NOT NULL, source VARCHAR(20) NOT NULL, captured_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
